from collections import defaultdict

def aggregate_search_results(
    search_results: List[SearchResult],
    group_by_field: str,
    aggregation_funcs: Optional[Dict[str, Callable]] = None
) -> Dict[str, Dict[str, Any]]:
    """Aggregate search results by a metadata field with optional statistics.

    Args:
        search_results: List of SearchResult objects to aggregate
        group_by_field: Metadata field name to group by
        aggregation_funcs: Optional dictionary mapping field_name to aggregation function.
            Example: {"score": max, "count": len}
            If None, defaults to count and average score per group

    Returns:
        Dictionary mapping group_value to aggregated statistics
        Example: {"tech": {"count": 5, "avg_score": 0.85, "max_score": 0.95}}
    """
    # Initialize dictionary to store aggregated results
    aggregated_results = {}

    # Helper function to extract field value from metadata
    def get_field_value(metadata: Dict[str, Any], field: str) -> Any:
        """Extract field value from metadata, handle missing values."""
        return metadata.get(field) if metadata else None

    # Iterate through each SearchResult
    for result in search_results:
        # Extract group value from metadata
        metadata = result.metadata if result.metadata else {}
        group_value = get_field_value(metadata, group_by_field)

        # Handle missing grouping field values
        if group_value is None or group_value == "":
            group_value = "unknown"

        # Initialize group entry if not exists
        if group_value not in aggregated_results:
            aggregated_results[group_value] = {
                "count": 0,
                "sum_scores": 0.0,
                "max_score": float("-inf"),
                "min_score": float("inf"),
                "custom_aggregations": {}
            }

        # Update default statistics
        group_data = aggregated_results[group_value]
        group_data["count"] += 1
        group_data["sum_scores"] += result.score

        if result.score > group_data["max_score"]:
            group_data["max_score"] = result.score

        if result.score < group_data["min_score"]:
            group_data["min_score"] = result.score

        # Apply custom aggregation functions if provided
        if aggregation_funcs:
            for field_name, agg_func in aggregation_funcs.items():
                # Extract field value (can be from metadata or top-level fields)
                field_value = result.score if field_name == "score" else get_field_value(metadata, field_name)

                # Initialize custom aggregation storage
                if field_name not in group_data["custom_aggregations"]:
                    group_data["custom_aggregations"][field_name] = []

                # Add value to custom aggregation collection
                group_data["custom_aggregations"][field_name].append(field_value)

    # Calculate final statistics for each group
    final_results = {}
    for group_value, group_data in aggregated_results.items():
        # Calculate average score
        avg_score = group_data["sum_scores"] / group_data["count"] if group_data["count"] > 0 else 0.0

        # Apply custom aggregation functions
        custom_stats = {}
        if aggregation_funcs and "custom_aggregations" in group_data:
            for field_name, values in group_data["custom_aggregations"].items():
                try:
                    custom_stats[field_name] = aggregation_funcs[field_name](values)
                except Exception as e:
                    custom_stats[field_name] = f"Error: {str(e)}"

        # Build final result dictionary
        final_results[group_value] = {
            "count": group_data["count"],
            "avg_score": round(avg_score, 4),
            "max_score": group_data["max_score"],
            "min_score": group_data["min_score"],
            **custom_stats
        }

    return final_results

